// // This module implements a 2-to-1 multiplexer with a 16-bit width, selecting between PC and Ra. The output 'out' will be equal to Ra when 'selEAB1' is low (0).
module top_module(selEAB1, PC, Ra, out);input selEAB1;
 input [15:0] PC, Ra;
 output [15:0] out;

 assign out = (selEAB1 == 1)? Ra: PC;endmodule
